const question = $.input.question;
const mode = $.input.agentMode || 'research';

const needsSearch = mode === 'research' || question.toLowerCase().includes('search') || question.toLowerCase().includes('find') || question.toLowerCase().includes('what is') || question.toLowerCase().includes('who is') || question.toLowerCase().includes('latest') || question.toLowerCase().includes('current');

return { question, mode, needsSearch, timestamp: new Date().toISOString() };

const results = $.steps.webSearch.response.results || [];

let sourcesText = '';
results.forEach((r, i) => {
  sourcesText += (i + 1) + '. ' + (r.title || 'Untitled') + '\n';
  sourcesText += '   URL: ' + r.url + '\n';
  if (r.publishedDate) sourcesText += '   Published: ' + r.publishedDate + '\n';
  sourcesText += '   ' + (r.text || '').slice(0, 1200) + '\n\n';
});

return { sourcesText, sourceCount: results.length, topSources: results.slice(0, 5).map(r => ({ title: r.title || r.url, url: r.url })) };

const mode = $.steps.classifyTask.output.mode;
const question = $.input.question;
const sources = $.steps.compileSources.output;

let prompt = 'You are an interactive AI agent with multiple capabilities. You have been given a task to complete.\n\n';
prompt += 'AGENT MODE: ' + mode + '\n';
prompt += 'USER TASK: ' + question + '\n\n';

if (sources.sourceCount > 0) {
  prompt += 'WEB SEARCH RESULTS (' + sources.sourceCount + ' sources):\n';
  prompt += sources.sourcesText + '\n\n';
}

prompt += 'CAPABILITIES:\n';
prompt += '- Web research and fact synthesis\n';
prompt += '- Mathematical calculations and logic\n';
prompt += '- Content generation (emails, summaries, code snippets)\n';
prompt += '- Data analysis and comparison\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Complete the user task thoroughly using the most relevant capability\n';
prompt += '- Cite sources by number when using web results\n';
prompt += '- Show your reasoning process\n';
prompt += '- Use Slack mrkdwn formatting: *bold*, _italic_, > for quotes, numbered lists\n';
prompt += '- Slack rules: use *bold* (NOT **bold**). No markdown tables. No # headings.\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "response": "<detailed response in Slack mrkdwn>",\n';
prompt += '  "toolsUsed": ["web_search", "analysis"],\n';
prompt += '  "confidence": "high|medium|low",\n';
prompt += '  "keyFindings": ["<finding1>", "<finding2>"],\n';
prompt += '  "followUpSuggestions": ["<suggestion1>", "<suggestion2>"]\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { response: raw, toolsUsed: ['analysis'], confidence: 'medium', keyFindings: [], followUpSuggestions: [] }; }

const ai = $.steps.parseAI.output;
const question = $.input.question;
const mode = $.steps.classifyTask.output.mode;
const sourceCount = $.steps.compileSources.output.sourceCount;
const topSources = $.steps.compileSources.output.topSources || [];

const confidenceEmoji = ai.confidence === 'high' ? ':large_green_circle:' : ai.confidence === 'low' ? ':red_circle:' : ':large_yellow_circle:';

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'AI Agent Response' } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Task:* ' + question } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Mode:* ' + mode + ' | *Tools:* ' + (ai.toolsUsed || []).join(', ') } });
blocks.push({ type: 'divider' });

const responseText = (ai.response || 'No response generated.').slice(0, 2900);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: responseText } });
blocks.push({ type: 'divider' });

if (ai.keyFindings && ai.keyFindings.length > 0) {
  let kfText = '*Key Findings:*\n';
  ai.keyFindings.forEach((f, i) => { kfText += (i + 1) + '. ' + f + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: kfText.slice(0, 1800) } });
}

if (ai.followUpSuggestions && ai.followUpSuggestions.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Follow-up Ideas:*\n' + ai.followUpSuggestions.map((s, i) => (i + 1) + '. ' + s).join('\n') } });
}

if (topSources.length > 0) {
  let srcText = '*Sources:*\n';
  topSources.slice(0, 3).forEach((s, i) => { srcText += (i + 1) + '. <' + s.url + '|' + (s.title || s.url).slice(0, 60) + '>\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: srcText } });
}

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: confidenceEmoji + ' Confidence: *' + (ai.confidence || 'medium') + '* | Sources: *' + sourceCount + '*' }] });

const fallback = 'AI Agent: ' + question;
return { blocks, fallback };
